SELECT u.user_name
FROM users u
JOIN account_changes ac ON u.user_id = ac.changed_by;

SELECT change_details
FROM account_changes
WHERE change_type = 'password' AND changed_date >= '2017-06-02';

SELECT users.user_name, user_roles.role_name
FROM users
JOIN user_roles ON users.role_id = user_roles.role_id;

SELECT audit_trail_details
FROM audit_trails
WHERE audit_trail_id = 1;
